#!/usr/bin/env python3
"""Generate the active post-specificity W3.5 task queue."""
from __future__ import annotations
from pathlib import Path
from report_link_utils import markdown_link
ROOT=Path(__file__).resolve().parents[1]; OUT=ROOT/'docs/planning/next-actions.md'; STATUS=ROOT/'docs/reports/project-status-generated.md'; GAP=ROOT/'docs/reports/research-gap-report.md'
TASKS=[
{"id":"STRATEGIC-003","priority":"high","title":"Execute candidate ablation and reconstruction","why":"Registered reasoning discrimination is complete and unique FARA discriminative capacity is refuted at the frozen scope. The universal-structure hypotheses must now be tested directly across the frozen corpus and alternative conceptual bases rather than inferred from FARA recurrence.","affected":["theory/evaluation/universal-structure-candidate-registry.json","theory/evaluation/reasoning-and-contrast-scope-v1.0.json","theory/evaluation/rcs-concrete-source-catalog-v1.0.json","theory/evaluation/w3-5-fara-specificity-result-v1.0.json","docs/research/universal-structure-discovery-target-v1.0.md"],"outcome":"Per-candidate ablation, reconstruction, equivalent-reintroduction, discrimination, and preserved-counterexample records, with every hypothesis receiving a terminal registered-scope classification or explicit unresolved result.","risk":"high","branch":"research/execute-w3-5-candidate-tests","pr":"Execute W3.5 candidate ablation and reconstruction"},
{"id":"STRATEGIC-004","priority":"high","title":"Complete W3.5 machinery cost and claim-impact audit","why":"W3.5 cannot authorize W5 without complete cost accounting, immutable evidence digests, preserved failures, and track-specific claim effects. The registered specificity result is a qualified negative and must remain visible in the closure package.","affected":["docs/research/w3-5-specificity-and-discovery-gate-v1.0.md","theory/evaluation/w3-5-specificity-and-discovery-gate.json","theory/evaluation/central-claim-registry.json","theory/evaluation/research-gates.json","theory/evaluation/w3-5-fara-specificity-result-v1.0.json"],"outcome":"A terminal W3.5 package satisfying every evidence-backed authorization requirement or an explicit unresolved result without erasing the negative FARA-uniqueness finding.","risk":"high","branch":"research/close-w3-5-adjudication","pr":"Close W3.5 adjudication and claim-impact audit"},
{"id":"STRATEGIC-005","priority":"blocked","title":"Assemble the finite-core theorem or strongest obstruction","why":"ASM-SC-001 through ASM-SC-003 remain open. W4, corpus freeze, factorization, registered discrimination, and qualified FARA-specificity are complete, but W5 remains blocked until candidate, cost, claim-impact, and failure artifacts are complete.","affected":["docs/research/s-core-construction-obstruction-ledger-v1.0.md","theory/evaluation/s-core-construction-obstruction-ledger.json","theory/evaluation/thm-target-001.json","theory/evaluation/central-claim-registry.json"],"outcome":"A bounded REP theorem, equivalence, countermodel, proper-subclass result, impossibility result, or explicit unresolved result consistent with the completed qualified-negative specificity evidence.","risk":"high","branch":"research/assemble-s-core-result","pr":"Assemble S_core theorem or obstruction"}]
def nav_links(): return [f"- README Command Center: {markdown_link(ROOT/'README.md',OUT)}",f"- Project Status: {markdown_link(STATUS,OUT)}",f"- Research Gaps: {markdown_link(GAP,OUT)}",f"- Next Actions: {markdown_link(OUT,OUT)}"]
def main()->int:
    ids=[x['id'] for x in TASKS]; assert len(ids)==len(set(ids))
    lines=['# Next Actions','','## Navigation','',*nav_links(),'','Generated by `python tools/generate_next_tasks.py` under the separated REP, ADJ, and USD program.','','W0-W4 are complete bounded REP packages. Corpus freeze, bounded GREL-FARA factorization, registered reasoning discrimination, and the qualified FARA-specificity result are complete. Unique FARA discriminative capacity is refuted at registered scope; all universal-structure candidates remain unresolved. Candidate ablation and reconstruction are next; W5 remains blocked.','','## Ranked Next Actions','']
    for task in TASKS:
        affected=[markdown_link(ROOT/path,OUT) for path in task['affected']]
        lines += [f"### {task['id']}: {task['title']}",'','- Source: central research program',f"- Priority: {task['priority']}",f"- Why it matters: {task['why']}",'- Affected files:',*[f'  - {item}' for item in affected],f"- Expected outcome: {task['outcome']}",f"- Risk level: {task['risk']}",f"- Suggested branch name: `{task['branch']}`",f"- Suggested PR title: `{task['pr']}`",'']
    lines += ['## Maintainer Task Briefs','','Each task must preserve `THM-TARGET-001`, `THM-US-TARGET-001`, `FAITHFUL-REP-001`, `P8-ROLE-001`, W0-W4, `RCS-CORPUS-001`, `W35-FACTOR-RESULT-001`, `W35-SCOPE-RESULT-001`, `W35-SPEC-RESULT-001`, both disputed cases, all failures, reintroduced machinery, and nonclaims. Do not retroactively alter admission or licensing records. Do not promote the bounded discriminator into a universal definition or FARA necessity. Do not begin W5 while `W3.5-SDG-001` remains unresolved or lacks linked immutable evidence.','','Validation commands:','','- `make research-check`','- `make health-fast`','','## Navigation','',*nav_links()]
    OUT.write_text('\n'.join(lines)+'\n',encoding='utf-8'); print(f"{OUT.relative_to(ROOT)} tasks={len(TASKS)}"); return 0
if __name__=='__main__': raise SystemExit(main())
